#include <stdio.h>
#include <stdbool.h>

#define MAX_N 100

int arr[MAX_N];
int n, target;

bool backtrack(int index, int currentSum) {
    // Base case: found exact sum
    if (currentSum == target) {
        return true;
    }

    // Pruning: exceeded target
    if (currentSum > target) {
        return false;
    }

    // No more elements
    if (index >= n) {
        return false;
    }

    // Pruning: check if remaining can reach target
    int remainingSum = 0;
    for (int i = index; i < n; i++) {
        remainingSum += arr[i];
    }
    if (currentSum + remainingSum < target) {
        return false;
    }

    // Include current element
    if (backtrack(index + 1, currentSum + arr[index])) {
        return true;
    }

    // Exclude current element
    return backtrack(index + 1, currentSum);
}

int main() {
    n = 6;
    arr[0] = 3; arr[1] = 34; arr[2] = 4;
    arr[3] = 12; arr[4] = 5; arr[5] = 2;
    target = 9;

    if (backtrack(0, 0)) {
        printf("Subset found!\n");
    } else {
        printf("No subset found.\n");
    }
    return 0;
}
